# lib/blog/sanitizer.ex
defmodule Blog.Sanitizer do
  @moduledoc """
  Sanitizes user-generated HTML content to prevent XSS attacks.
  Allows safe formatting tags while stripping dangerous elements.
  """

  # Define allowed tags and attributes for rich content
  def sanitize(html) when is_binary(html) do
    HtmlSanitizeEx.basic_html(html)
  end

  def sanitize(nil), do: ""

  # For more permissive rich content (still safe)
  def sanitize_rich(html) when is_binary(html) do
    HtmlSanitizeEx.html5(html)
  end

  def sanitize_rich(nil), do: ""
end

# lib/blog_web/live/post_live/show.ex
defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Sanitizer

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)

    {:ok,
     socket
     |> assign(:page_title, post.title)
     |> assign(:post, post)
     |> assign(:sanitized_content, Sanitizer.sanitize(post.content))}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto px-4 py-8">
      <article class="blog-post">
        <header class="mb-8">
          <h1 class="text-4xl font-bold text-gray-900 mb-2"><%= @post.title %></h1>
          <div class="text-gray-500 text-sm">
            <span>By <%= @post.author.name %></span>
            <span class="mx-2">·</span>
            <time datetime={@post.inserted_at}><%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %></time>
          </div>
        </header>

        <div class="prose prose-lg max-w-none">
          <%!--
            SECURITY NOTE: We sanitize user HTML content before rendering.
            NEVER use raw(@post.content) directly with user input.
            The content is sanitized in mount/3 using HtmlSanitizeEx
            which strips <script>, onclick handlers, javascript: URIs,
            and other XSS vectors while preserving safe formatting tags.
          --%>
          <%= Phoenix.HTML.raw(@sanitized_content) %>
        </div>

        <footer class="mt-12 pt-8 border-t border-gray-200">
          <div class="flex items-center gap-4">
            <.link navigate={~p"/posts"} class="text-blue-600 hover:underline">
              ← Back to all posts
            </.link>
            <%= if @post.tags != [] do %>
              <div class="flex gap-2">
                <%= for tag <- @post.tags do %>
                  <span class="bg-gray-100 text-gray-700 px-3 py-1 rounded-full text-sm">
                    <%= tag.name %>
                  </span>
                <% end %>
              </div>
            <% end %>
          </div>
        </footer>
      </article>
    </div>
    """
  end
end

# lib/blog_web/live/post_live/index.ex
defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Sanitizer

  @impl true
  def mount(_params, _session, socket) do
    posts =
      Posts.list_posts()
      |> Enum.map(fn post ->
        Map.put(post, :sanitized_excerpt, Sanitizer.sanitize(excerpt(post.content)))
      end)

    {:ok, assign(socket, :posts, posts)}
  end

  defp excerpt(nil), do: ""

  defp excerpt(content) when is_binary(content) do
    content
    |> HtmlSanitizeEx.strip_tags()
    |> String.slice(0, 300)
    |> Kernel.<>("...")
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto px-4 py-8">
      <h1 class="text-3xl font-bold mb-8">Blog Posts</h1>

      <div class="space-y-8">
        <%= for post <- @posts do %>
          <article class="border-b border-gray-200 pb-8">
            <h2 class="text-2xl font-semibold mb-2">
              <.link navigate={~p"/posts/#{post.id}"} class="text-blue-700 hover:underline">
                <%= post.title %>
              </.link>
            </h2>
            <p class="text-gray-500 text-sm mb-3">
              By <%= post.author.name %> · <%= Calendar.strftime(post.inserted_at, "%B %d, %Y") %>
            </p>
            <p class="text-gray-700"><%= post.sanitized_excerpt %></p>
          </article>
        <% end %>
      </div>
    </div>
    """
  end
end

# lib/blog/posts.ex - Context with sanitization on save
defmodule Blog.Posts do
  alias Blog.Repo
  alias Blog.Posts.Post
  alias Blog.Sanitizer

  import Ecto.Query

  def list_posts do
    Post
    |> order_by(desc: :inserted_at)
    |> preload([:author, :tags])
    |> Repo.all()
  end

  def get_post!(id) do
    Post
    |> preload([:author, :tags])
    |> Repo.get!(id)
  end

  def create_post(attrs) do
    # Sanitize content before persisting to database (defense in depth)
    attrs = sanitize_attrs(attrs)

    %Post{}
    |> Post.changeset(attrs)
    |> Repo.insert()
  end

  def update_post(%Post{} = post, attrs) do
    attrs = sanitize_attrs(attrs)

    post
    |> Post.changeset(attrs)
    |> Repo.update()
  end

  # Defense in depth: sanitize on write AND on read
  defp sanitize_attrs(%{"content" => content} = attrs) when is_binary(content) do
    Map.put(attrs, "content", Sanitizer.sanitize(content))
  end

  defp sanitize_attrs(%{content: content} = attrs) when is_binary(content) do
    Map.put(attrs, :content, Sanitizer.sanitize(content))
  end

  defp sanitize_attrs(attrs), do: attrs
end